)

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	visited := make([][]bool, m)
	for i := 0; i < m; i++ {
		visited[i] = make([]bool, n)
	}
	var count int64
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if grid[i][j] > 0 && !visited[i][j] {
				sum := int64(0)
				stack := [][]int{{i, j}}
				visited[i][j] = true
				for len(stack) > 0 {
					x, y := stack[len(stack)-1][0], stack[len(stack)-1][1]
					stack = stack[:len(stack)-1]
					sum += grid[x][y]
					for dx := -1; dx <= 1; dx++ {
						for dy := -1; dy <= 1; dy++ {
							abs_dx := dx
							if abs_dx < 0 {
								abs_dx = -abs_dx
							}
							abs_dy := dy
							if abs_dy < 0 {
								abs_dy = -abs_dy
							}
							if abs_dx+abs_dy == 1 {
