								ny := y + dy
								if nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0 {
									visited[nx][ny] = true
									stack = append(stack, []int{nx, ny})
								}
							}
						}
					}
				}
				if sum%k == 0 {
					count++
				}
			}
		}
	}
	return count
}
