```javascript
function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const visited = Array(m).fill().map(() => Array(n).fill(false));
    let count = 0;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                let sum = 0;
                const stack = [[i, j]];
                visited[i][j] = true;
                while (stack.length > 0) {
                    const [x, y] = stack.pop();
                    sum += grid[x][y];
                    for (let dx of [-1, 0, 1]) {
                        for (let dy of [-1, 0, 1]) {
                            if (Math.abs(dx) + Math.abs(dy) === 1) {
                                const nx = x + dx;
                                const ny = y + dy;
                                if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                                    visited[nx][ny] = true;
                                    stack.push([nx, ny]);
                                }
                            }
                        }
                    }
                }
                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
